### Hybrid LM Studio Configuration with Hosted Fallbacks

Source: https://github.com/openclaw/openclaw/blob/main/docs/gateway/local-models.md

This configuration prioritizes a hosted model (e.g., Anthropic Sonnet) as primary, with local MiniMax M2.1 and hosted Opus as fallbacks. It uses `models.mode: "merge"` to ensure hosted models remain available when the local setup is unavailable. This provides a balance between local performance and cloud reliability.

```json5
{
  "agents": {
    "defaults": {
      "model": {
        "primary": "anthropic/claude-sonnet-4-5",
        "fallbacks": ["lmstudio/minimax-m2.1-gs32", "anthropic/claude-opus-4-5"]
      },
      "models": {
        "anthropic/claude-sonnet-4-5": { "alias": "Sonnet" },
        "lmstudio/minimax-m2.1-gs32": { "alias": "MiniMax Local" },
        "anthropic/claude-opus-4-5": { "alias": "Opus" }
      }
    }
  },
  "models": {
    "mode": "merge",
    "providers": {
      "lmstudio": {
        "baseUrl": "http://127.0.0.1:1234/v1",
        "apiKey": "lmstudio",
        "api": "openai-responses",
        "models": [
          {
            "id": "minimax-m2.1-gs32",
            "name": "MiniMax M2.1 GS32",
            "reasoning": false,
            "input": ["text"],
            "cost": { "input": 0, "output": 0, "cacheRead": 0, "cacheWrite": 0 },
            "contextWindow": 196608,
            "maxTokens": 8192
          }
        ]
      }
    }
  }
}
```

